class Solution:
    def canConstruct(self, s: str, k: int) -> bool:
        count = {}
        for char in s:
            if char in count:
                count[char] += 1
            else:
                count[char] = 1
        odd = 0
        for val in count.values():
            if val % 2 != 0:
                odd += 1
        return odd <= k
